import os
import uuid
import pyclamd
import logging

log = logging.getLogger(__name__)

ALLOWED_EXTENSIONS = {'.pdf', '.docx', '.xlsx', '.png', '.jpg'}
MAX_SIZE_BYTES = 10 * 1024 * 1024  # 10MB
UPLOAD_DIR = os.environ.get('UPLOAD_DIR', 'uploads')


class FileUploadService:
    def __init__(self):
        try:
            self.scanner = pyclamd.ClamdUnixSocket()
            self.scanner.ping()
        except pyclamd.ConnectionError:
            log.warning('ClamAV not available, virus scanning disabled')
            self.scanner = None

    def validate_and_save(self, filename: str, file_data: bytes) -> dict:
        ext = os.path.splitext(filename)[1].lower()
        if ext not in ALLOWED_EXTENSIONS:
            raise ValueError(f'File type {ext} not allowed')
        if len(file_data) > MAX_SIZE_BYTES:
            raise ValueError(f'File too large (max {MAX_SIZE_BYTES // 1024 // 1024}MB)')
        if self.scanner:
            result = self.scanner.scan_stream(file_data)
            if result:
                virus = list(result.values())[0][1]
                raise ValueError(f'Virus detected: {virus}')
        safe_name = f'{uuid.uuid4().hex}{ext}'
        path = os.path.join(UPLOAD_DIR, safe_name)
        os.makedirs(UPLOAD_DIR, exist_ok=True)
        with open(path, 'wb') as f:
            f.write(file_data)
        return {'filename': safe_name, 'path': path, 'size': len(file_data)}
